import{_ as a,o as s,c as t,a2 as o}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"ECodex 1.0.0 发布说明","description":"","frontmatter":{},"headers":[],"relativePath":"release-notes/1.0.0.md","filePath":"release-notes/1.0.0.md","lastUpdated":1781591917000}'),i={name:"release-notes/1.0.0.md"};function d(l,e,n,r,c,h){return s(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="ecodex-1-0-0-发布说明" tabindex="-1">ECodex 1.0.0 发布说明 <a class="header-anchor" href="#ecodex-1-0-0-发布说明" aria-label="Permalink to &quot;ECodex 1.0.0 发布说明&quot;">​</a></h1><p>ECodex 1.0.0 是第一个 Windows 原生 SuperTerminal 稳定版。它把终端 Workspace、集成浏览器、脚本化自动化、会话恢复和 Windows 安装更新整合到一个桌面工作流中。</p><h2 id="推荐下载" tabindex="-1">推荐下载 <a class="header-anchor" href="#推荐下载" aria-label="Permalink to &quot;推荐下载&quot;">​</a></h2><table tabindex="0"><thead><tr><th>产物</th><th>适用场景</th><th>说明</th></tr></thead><tbody><tr><td><code>ecodex-win-x64-sc</code></td><td>大多数 Windows 10/11 用户</td><td>self-contained app 目录，不需要共享 .NET runtime。</td></tr><tr><td><code>ecodex-cli-win-x64</code></td><td>自动化脚本和 CI</td><td>仅命令行包，提供 <code>ecodex</code> 命令。</td></tr><tr><td>Velopack 安装器/feed</td><td>需要自动更新的用户</td><td>支持 <code>ecodex update check</code> 与 <code>ecodex update install</code>。</td></tr><tr><td>Inno Setup 安装器</td><td>传统桌面安装</td><td>创建快捷方式，卸载保留 <code>%USERPROFILE%\\.ecodex</code>。</td></tr><tr><td>MSIX 包</td><td>企业分发</td><td>适合受管环境。</td></tr></tbody></table><p>详细步骤见 <a href="./../installation">安装</a>。</p><h2 id="新特性" tabindex="-1">新特性 <a class="header-anchor" href="#新特性" aria-label="Permalink to &quot;新特性&quot;">​</a></h2><ul><li><strong>Terminal Workspace</strong>：支持多个 Workspace、Surface 与 split Pane。</li><li><strong>会话持久化</strong>：保存布局、terminal snapshots、browser metadata 与 trusted resume bindings。</li><li><strong>集成浏览器</strong>：在终端旁打开 WebView2 浏览器，保存 URL 与 history。</li><li><strong>浏览器 API</strong>：通过 <code>ecodex browser</code> 与 <code>ecodex.v2</code> 自动化 snapshot、locator、click、fill、hover、press、eval、screenshots、cookies、storage、console、dialog、download、highlight。</li><li><strong>短引用与 v2 命令行</strong>：使用 <code>window:N</code>、<code>workspace:N</code>、<code>surface:N</code>、<code>pane:N</code> 定位对象。</li><li><strong>Windows 集成</strong>：PATH、PowerShell completion、Windows Terminal profiles、doctor、update 与发布产物。</li></ul><h2 id="首次运行" tabindex="-1">首次运行 <a class="header-anchor" href="#首次运行" aria-label="Permalink to &quot;首次运行&quot;">​</a></h2><p>安装后运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ecodex doctor</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ecodex setup status</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ecodex completion powershell</span></span></code></pre></div><p>创建 Workspace 并尝试集成浏览器：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ecodex workspace create </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name demo </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cwd C:\\repo\\demo</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ecodex pane split right</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ecodex browser new https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">example.com</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ecodex status </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">json</span></span></code></pre></div><h2 id="升级注意事项" tabindex="-1">升级注意事项 <a class="header-anchor" href="#升级注意事项" aria-label="Permalink to &quot;升级注意事项&quot;">​</a></h2><ul><li>替换文件前先停止 <code>ecodex-app.exe</code>、<code>ecodex-daemon.exe</code> 和旧终端会话。</li><li>如果依赖自定义恢复绑定，请备份 <code>%USERPROFILE%\\.ecodex\\session.json</code> 与 <code>%USERPROFILE%\\.ecodex\\resume.json</code>。</li><li>卸载与更新默认保留 <code>%USERPROFILE%\\.ecodex</code>。</li><li>安装后运行 <code>ecodex doctor</code> 检查 ConPTY、WebView2、PATH、daemon 与 config 目录。</li></ul><h2 id="已知限制" tabindex="-1">已知限制 <a class="header-anchor" href="#已知限制" aria-label="Permalink to &quot;已知限制&quot;">​</a></h2><ul><li>ConPTY 需要 Windows 10 1809 / build 17763 或更新版本。</li><li>集成浏览器需要 WebView2 Runtime。</li><li><code>Release</code> 构建会发布 <code>ecodex-perf-report</code>，包含冷启动、<code>ecodex status</code>、<code>browser.snapshot</code>、session save 预算行。</li><li>浏览器自动化对非 P0 的 network、viewport、geolocation、trace、screencast 操作返回 <code>not_supported</code>，详见 <a href="./../browser-api">浏览器 API</a>。</li><li>发布阻塞项见 <a href="./../release-readiness">发布就绪</a>；1.0 门槛要求 P0 = 0、P1 &lt;= 3 且有规避方案。</li></ul><h2 id="更多文档" tabindex="-1">更多文档 <a class="header-anchor" href="#更多文档" aria-label="Permalink to &quot;更多文档&quot;">​</a></h2><ul><li><a href="./../getting-started">快速上手</a></li><li><a href="./../cli">命令行</a></li><li><a href="./../custom-commands">自定义命令</a></li><li><a href="./../session-restore">会话恢复</a></li><li><a href="./../troubleshooting">故障排查</a></li></ul>`,18)])])}const u=a(i,[["render",d]]);export{k as __pageData,u as default};
